        if (!xmlFile.exists() || !xmlFile.isFile()) {
            throw new IllegalArgumentException("Configuration file not found or is invalid: " + configPath);
        }

        try (InputStream inputStream = new FileInputStream(xmlFile)) {

            // 3. Initialize and strictly secure SAXParserFactory against XXE (XML External Entity) attacks
            SAXParserFactory saxFactory = SAXParserFactory.newInstance();

            // Disallow DOCTYPE declarations completely (Strongest XXE prevention)
            saxFactory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            // Disable external general entities
            saxFactory.setFeature("http://xml.org/sax/features/external-general-entities", false);
            // Disable external parameter entities
            saxFactory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            // Disable external DTDs
            saxFactory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
            saxFactory.setXIncludeAware(false);
            saxFactory.setNamespaceAware(true);

            SAXParser saxParser = saxFactory.newSAXParser();
            XMLReader xmlReader = saxParser.getXMLReader();

            // 4. Create a SAXSource using the secured XMLReader
            SAXSource saxSource = new SAXSource(xmlReader, new InputSource(inputStream));

            // 5. Create an empty DOM Document to hold the transformed result
            DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
            dbf.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            dbf.setNamespaceAware(true);
            DocumentBuilder db = dbf.newDocumentBuilder();
            Document emptyDocument = db.newDocument();

            // 6. Use a Transformer to bridge SAX and DOM (Converts SAX events to DOM nodes)
            TransformerFactory tf = TransformerFactory.newInstance();
            // Secure the TransformerFactory against external entity injection
            tf.setAttribute(XMLConstants.ACCESS_EXTERNAL_DTD, "");
            tf.setAttribute(XMLConstants.ACCESS_EXTERNAL_STYLESHEET, "");

            Transformer transformer = tf.newTransformer();
            DOMResult domResult = new DOMResult(emptyDocument);

            // Execute the transformation
            transformer.transform(saxSource, domResult);

            return (Document) domResult.getNode();

        } catch (Exception e) {
            // 7. Handle invalid XML format, parsing errors, and I/O exceptions
            throw new RuntimeException("Failed to securely parse the XML configuration file: " + e.getMessage(), e);
        }
    }
}
